"use strict";(self.webpackChunkkrateo_v_2_docs=self.webpackChunkkrateo_v_2_docs||[]).push([[1016],{196:(e,t,o)=>{o.r(t),o.d(t,{assets:()=>c,contentTitle:()=>r,default:()=>l,frontMatter:()=>a,metadata:()=>s,toc:()=>d});var n=o(7624),i=o(2172);const a={},r="How It Works",s={id:"key-concepts/kcf/how-it-works",title:"How It Works",description:"The platform is built around a pipeline that moves data from external API sources into a database, and then acts on that data through optimization and forecasting. Each stage of the pipeline is managed by a dedicated Kubernetes operator or service, coordinated through custom resources.",source:"@site/versioned_docs/version-3.0.0/20-key-concepts/30-kcf/20-how-it-works.md",sourceDirName:"20-key-concepts/30-kcf",slug:"/key-concepts/kcf/how-it-works",permalink:"/key-concepts/kcf/how-it-works",draft:!1,unlisted:!1,tags:[],version:"3.0.0",sidebarPosition:20,frontMatter:{},sidebar:"tutorialSidebar",previous:{title:"Krateo Composable FinOps",permalink:"/key-concepts/kcf/finops-introduction"},next:{title:"FinOps Operator Exporter",permalink:"/key-concepts/kcf/finops-components/finops-operator-exporter"}},c={},d=[{value:"Data Collection: Exporters and Scrapers",id:"data-collection-exporters-and-scrapers",level:2},{value:"Data Collection: The FOCUS Operator",id:"data-collection-the-focus-operator",level:2},{value:"Data Storage: The Database Handler",id:"data-storage-the-database-handler",level:2},{value:"Optimization: OPA Policies and the Webhook",id:"optimization-opa-policies-and-the-webhook",level:2},{value:"Optimization: Forecasting with KServe",id:"optimization-forecasting-with-kserve",level:2},{value:"The Feedback Loop",id:"the-feedback-loop",level:2}];function h(e){const t={code:"code",h1:"h1",h2:"h2",li:"li",p:"p",ul:"ul",...(0,i.M)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.h1,{id:"how-it-works",children:"How It Works"}),"\n",(0,n.jsx)(t.p,{children:"The platform is built around a pipeline that moves data from external API sources into a database, and then acts on that data through optimization and forecasting. Each stage of the pipeline is managed by a dedicated Kubernetes operator or service, coordinated through custom resources."}),"\n",(0,n.jsx)(t.h2,{id:"data-collection-exporters-and-scrapers",children:"Data Collection: Exporters and Scrapers"}),"\n",(0,n.jsxs)(t.p,{children:["The fundamental unit of data collection is the ",(0,n.jsx)(t.code,{children:"ExporterScraperConfig"})," custom resource. When one is created, the ",(0,n.jsx)(t.code,{children:"finops-operator-exporter"})," reads its ",(0,n.jsx)(t.code,{children:"exporterConfig"})," and ",(0,n.jsx)(t.code,{children:"scraperConfig"})," sections and provisions three Kubernetes resources: a Deployment running a generic Prometheus exporter, a ConfigMap containing the exporter configuration mounted as a volume inside the deployment, and a Service exposing the deployment's metrics endpoint. It then creates a CR for the ",(0,n.jsx)(t.code,{children:"finops-operator-scraper"}),", which spins up a scraper configured to periodically connect to that Service and upload the collected data to the database through the ",(0,n.jsx)(t.code,{children:"finops-database-handler"}),"."]}),"\n",(0,n.jsx)(t.p,{children:"The exporter itself is a generic webservice that calls an external API on a configurable polling interval and translates the response into Prometheus-format metrics. The API endpoint is referenced via a Kubernetes Secret containing the base URL, while the path and HTTP verb are specified directly in the CR. Additional variables can be injected into the URL at runtime, including references to environment variables available inside the exporter container, for example, Kubernetes service addresses. This makes it possible to point the exporter at internal cluster services such as a Prometheus instance, in addition to external cloud provider APIs."}),"\n",(0,n.jsxs)(t.p,{children:["The ",(0,n.jsx)(t.code,{children:"metricType"})," field controls how the exporter interprets the API response:"]}),"\n",(0,n.jsxs)(t.ul,{children:["\n",(0,n.jsxs)(t.li,{children:["When set to ",(0,n.jsx)(t.code,{children:"cost"}),", the endpoint is expected to return a FOCUS-format CSV or JSON file. The exporter parses it and exposes the cost fields as Prometheus metrics."]}),"\n",(0,n.jsxs)(t.li,{children:["When set to ",(0,n.jsx)(t.code,{children:"resource"}),", the endpoint is expected to return usage metrics according to a predefined JSON/OpenAPI schema. The ",(0,n.jsx)(t.code,{children:"additionalVariables"})," field must include a ",(0,n.jsx)(t.code,{children:"ResourceId"})," to link usage records back to their corresponding cost records in the database."]}),"\n",(0,n.jsxs)(t.li,{children:["When set to ",(0,n.jsx)(t.code,{children:"generic"}),", schema validation is removed entirely, allowing arbitrary data to be collected. In this mode, ",(0,n.jsx)(t.code,{children:"valueColumnIndex"})," identifies which field contains the metric value. The column index for CSV, or the index among alphabetically sorted keys for JSON. ",(0,n.jsx)(t.code,{children:"metricName"})," gives the metric a name that the scraper can use to select it specifically when scraping from an endpoint that exposes many metrics, such as a Prometheus API."]}),"\n"]}),"\n",(0,n.jsxs)(t.p,{children:["The ",(0,n.jsx)(t.code,{children:"generic"})," metric type is also the mechanism used to pull data from an existing Prometheus deployment inside the cluster, making it possible to collect pod and node metrics such as CPU usage without relying on external data from a cloud provider."]}),"\n",(0,n.jsx)(t.h2,{id:"data-collection-the-focus-operator",children:"Data Collection: The FOCUS Operator"}),"\n",(0,n.jsxs)(t.p,{children:["For cases where cost data is already known at definition time and does not need to be fetched from an external API, the ",(0,n.jsx)(t.code,{children:"finops-operator-focus"})," provides a more direct path. A ",(0,n.jsx)(t.code,{children:"FocusConfig"})," CR contains the full set of FOCUS fields populated inline. The operator reads this CR and internally creates an ",(0,n.jsx)(t.code,{children:"ExporterScraperConfig"})," that points the exporter at the Kubernetes API server itself, reading the ",(0,n.jsx)(t.code,{children:"FocusConfig"})," CR as the data source. From that point on, the standard exporter and scraper pipeline takes over, meaning the FOCUS operator is effectively a convenience wrapper that feeds hand-authored cost records into the same collection infrastructure."]}),"\n",(0,n.jsx)(t.h2,{id:"data-storage-the-database-handler",children:"Data Storage: The Database Handler"}),"\n",(0,n.jsxs)(t.p,{children:["All collected data lands in CrateDB, a distributed SQL database. Direct access to CrateDB is mediated entirely by the ",(0,n.jsx)(t.code,{children:"finops-database-handler"}),", a webservice that acts as a proxy between the rest of the platform and the database. Authentication credentials are stored in a Kubernetes Secret, and RBAC on that secret controls who can interact with the database through the handler."]}),"\n",(0,n.jsxs)(t.p,{children:["The handler exposes two categories of endpoints. The ",(0,n.jsx)(t.code,{children:"/upload"})," endpoint receives data in chunks and writes it directly into the specified table, with the ",(0,n.jsx)(t.code,{children:"type"})," parameter distinguishing between cost and resource tables. The ",(0,n.jsx)(t.code,{children:"/compute"})," family of endpoints manages Python notebooks: notebooks can be uploaded with or without overwrite, listed, deleted, and executed. When a notebook is executed, the handler injects database connection details as arguments, so notebooks can open a CrateDB connection and run arbitrary SQL queries without embedding credentials in their code. The output format of a notebook execution is completely free-form, allowing notebooks to serve as custom API endpoints whose response shape is defined entirely by the notebook author."]}),"\n",(0,n.jsxs)(t.p,{children:["Notebooks are registered into the handler through the ",(0,n.jsx)(t.code,{children:"finops-database-handler-uploader"}),", which watches ",(0,n.jsx)(t.code,{children:"Notebook"})," CRs. Each CR specifies either ",(0,n.jsx)(t.code,{children:"inline"})," code or an ",(0,n.jsx)(t.code,{children:"api"})," reference to a remote Python file, and the name of the CR becomes the name of the compute endpoint in the handler. This means adding a new analytical capability to the platform is a matter of writing a Python script and applying a CR, with no changes to the handler service itself."]}),"\n",(0,n.jsxs)(t.p,{children:["Tags in cost data must follow a specific JSON object format within the ",(0,n.jsx)(t.code,{children:"Tags"})," column. This structure allows the handler to parse and store them in a way that supports key-based querying directly in SQL, for example filtering records by organizational unit or environment."]}),"\n",(0,n.jsx)(t.h2,{id:"optimization-opa-policies-and-the-webhook",children:"Optimization: OPA Policies and the Webhook"}),"\n",(0,n.jsxs)(t.p,{children:["Optimization is applied to compositions through a mutating webhook backed by Open Policy Agent. Every time a composition is created or updated, the webhook intercepts the request and evaluates a set of Rego policies against it. Policies have access to data stored in the database through notebook endpoints on the ",(0,n.jsx)(t.code,{children:"finops-database-handler"}),", which means optimization decisions can be informed by actual collected cost and usage data."]}),"\n",(0,n.jsxs)(t.p,{children:["Policies are divided into two categories by the event that triggers them. Day-1 policies fire on a ",(0,n.jsx)(t.code,{children:"CREATE"})," event and govern initial placement decisions, for example, selecting the region and deployment time that minimizes carbon intensity for a new Virtual Machine. Day-2 policies fire on ",(0,n.jsx)(t.code,{children:"UPDATE"})," events, which are triggered either by real resource changes or by a periodic CronJob embedded in the composition definition that relabels the resource on a schedule to force a re-evaluation. A day-2 example is the moving window algorithm, which scans historical usage timeseries to identify virtual machines consuming more resources than their workload actually requires, and surfaces a rightsizing recommendation in the ",(0,n.jsx)(t.code,{children:"spec.optimization"})," field of the composition, where it becomes visible in the frontend."]}),"\n",(0,n.jsx)(t.h2,{id:"optimization-forecasting-with-kserve",children:"Optimization: Forecasting with KServe"}),"\n",(0,n.jsxs)(t.p,{children:["Policies that require predictions about future behavior, such as the carbon-aware scheduler, depend on a forecasting layer built on KServe and managed by the ",(0,n.jsx)(t.code,{children:"kserve-controller"}),". This controller introduces two custom resources. An ",(0,n.jsx)(t.code,{children:"InferenceConfig"})," defines the static properties of a model deployment: the KServe endpoint URL, the runner image to use, and the storage backend configuration for both input and output. An ",(0,n.jsx)(t.code,{children:"InferenceRun"})," is an execution trigger: it references an ",(0,n.jsx)(t.code,{children:"InferenceConfig"}),", provides runtime parameters such as table names and query filters, and optionally includes a cron schedule."]}),"\n",(0,n.jsxs)(t.p,{children:["When an ",(0,n.jsx)(t.code,{children:"InferenceRun"})," is created, the controller assembles a Contract, a JSON document containing all the information the runner needs, and mounts it into a Kubernetes Job via a ConfigMap. If a schedule is specified, a CronJob is created instead. The runner image is a lightweight process whose only responsibilities are to fetch input data from the configured storage backend, call the KServe model endpoint with that data, and write the results back to the output backend. All data transformation logic lives outside the runner, in notebooks registered with the ",(0,n.jsx)(t.code,{children:"finops-database-handler"}),". The input notebook prepares the query and shapes the data into the format the model expects; the output notebook receives the raw inference result and writes it into the appropriate database table in a form that OPA policies and the scraper pipeline can consume."]}),"\n",(0,n.jsxs)(t.p,{children:["The storage backend configuration in both ",(0,n.jsx)(t.code,{children:"InferenceConfig"})," and ",(0,n.jsx)(t.code,{children:"InferenceRun"})," is deliberately schema-free, meaning any storage provider can be supported by providing a runner image that knows how to interpret that section of the contract. The Krateo-native runner uses the ",(0,n.jsx)(t.code,{children:"finops-database-handler"})," notebook endpoints for both input and output, keeping all data access within the platform's standard authentication and access control boundaries."]}),"\n",(0,n.jsx)(t.h2,{id:"the-feedback-loop",children:"The Feedback Loop"}),"\n",(0,n.jsxs)(t.p,{children:["The architecture is designed to close on itself. Compositions provision ",(0,n.jsx)(t.code,{children:"ExporterScraperConfig"})," resources alongside the cloud resources they manage, so the platform begins collecting actual cost and usage metrics for every resource it deploys. That data flows into CrateDB. The ",(0,n.jsx)(t.code,{children:"kserve-controller"})," runs forecasting models on a schedule against that data and writes predictions back into the database. OPA policies read both historical and forecasted data when evaluating day-2 optimizations. The results of those optimizations are applied back to the composition, potentially changing the resource configuration, which in turn changes the metrics being collected. Over time, this loop should converge toward the resource allocation that best satisfies the target optimization objective, whether that is cost, carbon intensity, or any other metric the platform has been configured to track."]})]})}function l(e={}){const{wrapper:t}={...(0,i.M)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(h,{...e})}):h(e)}},2172:(e,t,o)=>{o.d(t,{I:()=>s,M:()=>r});var n=o(1504);const i={},a=n.createContext(i);function r(e){const t=n.useContext(a);return n.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function s(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:r(e.components),n.createElement(a.Provider,{value:t},e.children)}}}]);